"""
MKT Original Commentary — Job chapters 19–21
Run: python3 scripts/zc-original-job-19-21.py
Verses: ch19×29 (minus v25 already present) + ch20×29 + ch21×34 = 91 new entries

Key decisions in this range:
- go'el (19:25): already written; script skips it via merge_comm
- ḥāmās (19:7): 'violence/injustice' — carry meaning across the Psalms parallel
- bᵉʿôr šinnāy (19:20): 'skin of my teeth' — unique hapax idiom
- ch21 as theodicy inversion: Job challenges the two-retribution formula of the friends
- Zophar ch20 uses vivid scatological/venom imagery for the wicked's fate
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JOB = {
  "19": {
    "1": "<p><em>wayyaʿan ʾîyôḇ wayyōʾmar</em>: 'Then Job answered and said.' The standard dialogue-opening formula appears 28 times in the book; its repetition creates the rhythm of a formal disputation. Job's response here opens his most extended and passionate speech, moving from accusation of the friends to the transcendent confession of vv.23-27.</p>",
    "2": "<p><em>ʿaḏ-ʾānāh tᵉḏaʾᵃḇûn nap̄šî ûṯᵉdakkᵉʾûn ḇiḏḇārîm</em>: 'How long will you torment my soul and crush me with words?' <em>Dāʾaḵ</em> (crush, be dimmed/faint) is used of a lamp going out (Isa 42:3; 43:17) and of the spirits sinking. <em>Dākāʾ</em> is more violent — to shatter, reduce to powder (Ps 90:3; 94:5). The pairing: they torment his living inner self (<em>nepeš</em>) and simultaneously destroy him with verbal force. The cruelty the friends inflict with language is presented as physical-grade violence against Job's person.</p>",
    "3": "<p><em>zeh ʿeśer pᵉʿāmîm takᵉlîmûnî</em>: 'Ten times now you have reproached me.' <em>Ten times</em> is likely idiomatic for 'repeatedly' (cf. Gen 31:7; Num 14:22) rather than a precise count of speech rounds. <em>Kālaṃ</em> (to humiliate, put to shame) describes public dishonor — the social violence of stripping someone of their standing before witnesses. <em>Lōʾ-ṯēḇōšû takkᵉrû-lî</em>: 'you are not ashamed to wrong me' — the lack of shame compounds the offense; they have no moral brake on their verbal attacks.</p>",
    "4": "<p><em>wᵉʾap̄ ʾim-šāgîṯî ʾittî tālîn mešûḡāṯî</em>: 'Even if I have truly erred, my error remains with me.' <em>Šāgāh</em> = to go astray, err inadvertently (Lev 4:13; Num 15:28; Prov 19:27). The condition is hypothetical ('even if'); Job does not concede the point. The verb's semantic range emphasizes unintentional sin rather than deliberate transgression — even at its most modest, his admission would be only of an error, not of the guilt Eliphaz, Bildad, and Zophar are asserting. <em>Ittî tālîn</em>: 'it lodges with me' — the error, if any, remains in his own sphere; it does not constitute grounds for the friends' attack.</p>",
    "5": "<p><em>ʾim-ʾāmnām ʿālāy taḡdîlû wᵉṯôkîḥû ʿālay ḥerpātî</em>: 'If you truly exalt yourselves over me and press my disgrace against me as evidence.' <em>Gādal ʿālay</em> (exalt yourselves over me) is the posture of domination and condescension. <em>Tôkîaḥ</em> (from <em>yākaḥ</em> = to argue/reprove/adjudicate) — their proof-from-disgrace reasoning: taking Job's suffering as evidence of guilt is a category error that the entire book exists to correct. The friends' logic is the proto-retribution theology Job is dismantling.</p>",
    "6": "<p><em>dᵉʿû ʾēp̄ô kî-ʾĕlôah ʿiwwᵉṯanî ûmṣûḏô ʿālay hiqqîp̄</em>: 'Know then that God has wronged me (<em>ʿiwwᵉṯanî</em>) and thrown his net around me.' <em>ʿĀwat</em> (to bend, pervert, twist) is a legal term for injustice and distortion of judgment (Lam 3:36; Amos 8:5). Job dares to say that what God has done to him is, by the normal standard of justice, perversion. <em>Mᵉṣûḏāh</em> (net/siege-works) from <em>ṣuḏ</em> (to hunt); the hunting-net image opens the extended military metaphor that runs through vv.6-12. God as hunter and besieger rather than protector.</p>",
    "7": "<p><em>hēn ʾeṣʿaq ḥāmās wᵉlōʾ ʾeʿāneh</em>: 'I shout &#8220;Violence!&#8221; (<em>ḥāmās</em>) but no one answers.' <em>Ḥāmās</em> is one of the weightiest Hebrew words for wrongful harm — the word used of the violence that provoked the flood (Gen 6:11; 6:13), the blood of Abel (Hab 2:8), and prophetic indictments throughout (Amos 3:10; Ezek 7:11). By crying <em>ḥāmās</em>, Job invokes the full legal-moral weight of injustice; it is the victim's cry when the offense rises to God's attention. The silence from the heavens — no answer, no verdict — is the theological crisis at the core of the book.</p>",
    "8": "<p><em>ʾorḥî gāḏar wᵉlōʾ ʾeʿĕbōr wᵉʿal nᵉṯîḇôṯay ḥōšeḵ yāśîm</em>: 'He has blocked my way so I cannot pass; he has put darkness over my paths.' The imagery of blocked paths and enforced darkness frames Job's situation as imprisonment by divine agency. <em>Gāḏar</em> (to wall up, block) is used in Lam 3:7 ('he has walled me in so I cannot escape') and Hos 2:6 ('I will hedge up her way with thorns'). The blocked path and darkened way together invert the protective guidance language of Ps 23:3 ('he leads me in right paths') and Ps 119:105 ('your word is a lamp to my feet').</p>",
    "9": "<p><em>kᵉḇôḏî mēʿālay hip̄šîṭ wᵉʿăṭeret rōʾšî lāqāḥ</em>: 'He has stripped me of my honor (<em>kāḇôḏ</em>) and taken the crown (<em>ʿăṭāret</em>) from my head.' <em>Kāḇôḏ</em> (honor/glory/weight) is the fundamental social-moral currency in the OT; its stripping is public humiliation at the most profound level. <em>ʿĂṭāret rōʾš</em> (the crown of the head) appears as a symbol of status and dignity (Prov 4:9; 12:4; 17:6). The two images together — robes stripped and crown removed — are the language of dethronement and disgrace: Job's former eminence (ch. 29) has been publicly annulled by God's action.</p>",
    "10": "<p><em>yittᵉṣēnî missābîḇ wāʾēlek wayyasēaʿ kāʾēṣ tiqwāṯî</em>: 'He has broken me down on every side and I am gone; he has pulled up my hope like a tree.' <em>Nāsaʿ</em> is the verb used for uprooting tent pegs and breaking camp (Exod 12:37; 17:1; Num 9:17) — the nomadic image of a total displacement. <em>Tiqwāh</em> (hope, expectation — literally 'that toward which one looks forward') is a key wisdom term. Job's hope is not merely diminished but uprooted, its roots torn out — the image makes clear this is not discouragement but ontological devastation.</p>",
    "11": "<p><em>wayyaḥar ʿālay ʾappô wayyaḥšᵉḇēnî lô kᵉṣārāyw</em>: 'He has kindled his wrath against me and counted me among his enemies.' <em>Ḥārāh ʾap̄</em> (his anger burns) is the standard expression for divine wrath in action (Exod 4:14; Num 11:10; 32:13). To be counted among God's <em>ṣārîm</em> (adversaries, enemies, those who press against) is the most extreme possible statement about Job's condition — he is not merely abandoned but positionally assigned to the category of God's enemies. The theological shock is that Job knows himself innocent of the conduct that would deserve enemy-status.</p>",
    "12": "<p><em>yaḥad yāḇōʾû gᵉḏûḏāyw wayyiśpᵉlû ʿālay darkām wayyaḥănû sāḇîḇ lᵉʾohᵃlî</em>: 'His troops advance together; they heap up siege ramps against their way against me and encamp around my tent.' <em>Gᵉḏûḏ</em> (marauding troop, raiding party) — a military force. <em>Sālaḥ derek</em> (heap up siege ramp) is the technical vocabulary of ancient siege warfare (cf. 2 Sam 20:15; Isa 37:33). The military metaphor is extended: God is a general conducting a systematic siege of a single individual. Job's tent (the last remnant of his domestic life) is surrounded. The image is grotesque in proportion — infinite divine power mobilized against one helpless man.</p>",
    "13": "<p><em>ʾaḥay mēʿālay hirḥîq wayyōdᵉʿay ʾak-zārû mimmennî</em>: 'He has put my brothers far from me; those who knew me have become wholly estranged.' The catalogue of abandoned relationships in vv.13-19 is a carefully structured social inventory working inward: brothers → acquaintances → relatives → familiar friends → household guests → servants → wife → children's family → companions. Each relationship, which in ANE culture carried obligation of loyalty, has been severed. <em>Zûr</em> (estranged, foreign, a stranger) — those who knew him now experience him as an alien, not as a person they recognize.</p>",
    "14": "<p><em>ḥāḏᵉlû qᵉrôbāy ûmᵉyuddāʿay šᵉḵēḥûnî</em>: 'My relatives have failed me, and my familiar friends have forgotten me.' <em>Ḥāḏal</em> (to cease, desist, fail) — they have simply stopped; the relational obligations they once performed have been discontinued. <em>Šāḵaḥ</em> (to forget) — the forgetting that in Israel's theology was the deepest relational failure (God 'forgetting' Israel in Isa 49:14; Job 'forgetting' God in 8:13). The friends have done what the faithless do: treated covenant relationships as optional when they become costly.</p>",
    "15": "<p><em>gārê ḇêṯî wᵉʾamᵉhōṯay lᵉzār taḥšᵉḇûnî nāḵrî hāyîṯî bᵉʿênêhem</em>: 'Those in my house and my female servants count me as a stranger; I have become a foreigner in their eyes.' <em>Zār</em> (stranger, alien, outsider) and <em>nāḵrî</em> (foreign, from another nation) are the strongest words for social exclusion — Job is now 'a foreigner' in his own household. This inverts the social world of ch. 29-31: the master of a household whose servants honored him is now unrecognized in his own house. The reversal is complete when even those who share physical space treat him as an intruder.</p>",
    "16": "<p><em>lᵉʿaḇdî qārāʾtî wᵉlōʾ yaʿăneh bᵉp̄î ʾeṯḥannen-lô</em>: 'I called my servant, but he gave me no answer; I had to beg him with my own mouth.' The collapse of the master-servant hierarchy: the servant who would previously have come at a word now does not answer, and the master must beg — literally supplicate (<em>ḥānan</em> = to implore, entreat favor). <em>Ḥānan</em> is the word used for prayer before God; here it is degraded to a plea to an ignoring slave. The reversal demonstrates that Job's former social power has been entirely stripped.</p>",
    "17": "<p><em>rûḥî zārāh lᵉʾišṯî wᵉḥannōṯî liḇnê ḇiṭnî</em>: 'My breath is repulsive to my wife; I am loathsome to the children of my own body.' <em>Rûaḥ</em> (breath/spirit) — the intimacy that breath represents makes the repulsion more visceral: the most intimate physical marker of presence (breath) is the exact thing his wife finds repellent. <em>Ḥānan liḇnê ḇiṭnî</em>: 'imploring the sons of my womb' — <em>beṭen</em> usually refers to the mother's womb, but here applied to Job's own children with an unusual intimacy. These are the children born from his own body and they too require supplication.</p>",
    "18": "<p><em>gam-ʿᵉwîlîm māʾăsû bî ʾāqûmāh waydabbᵉrû-bî</em>: 'Even young children despise me; when I stand up they speak against me.' <em>ʿĀwîl</em> (young child, child — sometimes child of low social standing) — even those who command no social authority openly mock Job. The phrase <em>ʾāqûmāh waydabbᵉrû-bî</em> ('when I rise, they speak against me') may imply that merely making a move — trying to assert some presence or dignity — provokes verbal attack from the lowest social tier. The inversion of Job's ch. 29 honor is complete: previously elders fell silent when he rose (29:9); now children jeer.</p>",
    "19": "<p><em>tāʿᵃḇûnî kāl-mᵉṯê sōḏî waʾᵃhāḇtî hāp̄ᵉḵû-bî</em>: 'All my intimate companions abhor me; those I loved have turned against me.' <em>Sôḏ</em> (intimate circle, secret counsel, close associates) — the word for the innermost ring of trusted friendship (Jer 23:18; Ps 25:14; Prov 3:32; 11:13). The abhorrence (<em>tāʿaḇ</em> = to abhor, detest) of those in the innermost circle is the final and most devastating betrayal. <em>ʾĀhăḇtî</em> (those I loved) — the emotional vocabulary here is striking: Job describes these relationships with the language of love, making the turning-against an act of betrayal at the most intimate level.</p>",
    "20": "<p><em>bᵉʿôrî ûḇiḇśārî dāḇᵉqāh ʿaṣmî wāʾitmallēṭāh bᵉʿôr šinnāy</em>: 'My bones cling to my skin and my flesh; I have escaped with the skin of my teeth.' <em>Bᵉʿôr šinnāy</em> is a unique hapax expression — literally 'in the skin of my teeth' — meaning escaped with absolutely nothing, by the barest margin. The teeth have no skin, so the phrase describes zero margin — survival of less than the minimum. <em>Dāḇaq</em> (to cling, cleave) — normally used of covenant loyalty (Gen 2:24; Ruth 1:14) is here used for bones clinging to skin because the flesh has wasted away; the word of marital union is applied to the grotesque adhesion of disease.</p>",
    "21": "<p><em>ḥonnûnî ḥonnûnî ʾattem rēʿāy kî yaḏ-ʾĕlôah nāḡᵉʿāh bî</em>: 'Have pity on me, have pity on me, O my friends, for the hand of God has struck me.' The doubled <em>ḥonnûnî</em> (be gracious to me, have mercy on me) is an intensification — the same verb used in prayer to God (Ps 6:2; 30:10; 31:9; 56:1) is now directed at humans. Job applies to his friends the vocabulary of petitionary prayer, underscoring both his desperation and the irony: those from whom he begs mercy are the ones most persistently adding to his suffering. <em>Yaḏ ʾĕlôah nāḡᵉʿāh bî</em>: 'the hand of God has touched/struck me' — <em>nāgaʿ</em> (to touch, smite, reach) is the verb from 1:11 and 2:5 where the Adversary predicted Job would 'curse God to his face' if God's hand touched him. Job acknowledges the touch but does not curse.</p>",
    "22": "<p><em>lāmmāh tirḏᵉp̄ûnî kēʾl ûmibᵉśārî lōʾ ṯiśbāʿû</em>: 'Why do you pursue me like God, and are not satisfied with my flesh?' <em>Rāḏap̄</em> (pursue, chase) — the word of relentless hunting. By pursuing Job 'like God' (<em>kēʾl</em>), Job accuses the friends of acting with divine-scale relentlessness against a human being. They are not merely critical advisers but persecutors. <em>Mibbᵉśārî lōʾ ṯiśbāʿû</em>: 'you are not satisfied with my flesh' — the appetite-for-flesh imagery suggests predatory consumption; the friends have devoured his honor and reputation and still want more.</p>",
    "23": "<p><em>mî-yittēn ʾēp̄ô wᵉyikkāṯᵉḇû miллāy</em>: 'O that my words were written down!' The longing for written testimony is the legal act of creating a permanent record that cannot be denied. <em>Yikkāṯᵉḇû</em> (niphal = 'were written') — the passive formulation leaves open who would inscribe them. <em>Millîm</em> (words, discourse) — specifically legal speech, not merely conversation. Job wants an irrefutable deposition that will outlast the moment and the witnesses. The desire for permanent testimony anticipates the divine answer: God will vindicate Job (42:7-9), and the book itself becomes the permanent record Job longed for.</p>",
    "24": "<p><em>bᵉʿēṭ bārzel wᵉʿōp̄eret laʿaḏ bᵉṣûr yᵉḥōṣᵉḇûn</em>: 'That with an iron pen and lead they were cut into the rock forever!' <em>ʿĒṭ bārzel</em> (iron stylus) — a sharp iron tool for carving; <em>ʿōp̄eret</em> (lead) poured into the cuts to make them permanent and visible. The technology of rock inscription with metal and lead filling was practiced in the ancient world to create indelible monuments. <em>Laʿaḏ</em> (forever, perpetually) — Job wants testimony that outlasts any human witness. The irony: Job desired his words cut permanently in rock; instead they have been preserved in the most-read book of world literature.</p>",
    "26": "<p><em>wᵉʾaḥar ʿôrî niqqᵉp̄û-zōʾt ûmibbᵉśārî ʾeḥĕzeh ʾĕlôah</em>: 'And after my skin is thus destroyed, yet from within my flesh I shall see God.' This verse (with v.27) is one of the most textually disputed passages in the OT. The key question is whether <em>mibbᵉśārî</em> means 'from my flesh' (i.e., still in the body = bodily resurrection) or 'from after/away from my flesh' (i.e., as a disembodied spirit). The Hebrew preposition <em>min</em> is ambiguous. The verb <em>ḥāzāh</em> (to see, behold — especially used of prophetic vision and direct divine encounter, Exod 24:11; Ps 17:15; 63:2) adds force to the statement: not mere knowledge of God but direct visual encounter.</p>",
    "27": "<p><em>ʾăšer ʾănî ʾeḥĕzeh-lî wᵉʿênay rāʾû wᵉlōʾ-zār kālû ḵilᵉyōṯay bᵉḥēqî</em>: 'Whom I myself shall see, and my own eyes shall behold — not a stranger's eyes. My heart fails within me with longing.' The emphatic personal pronouns: <em>ʾănî</em> (I myself), <em>ʿênay</em> (my own eyes), <em>wᵉlōʾ-zār</em> (not a stranger's, not another's) — Job insists on personal, individual, direct encounter, not a third-party report. <em>Kālû ḵilᵉyōṯay bᵉḥēqî</em>: 'my kidneys (<em>kilyôt</em>) fail within my bosom with longing' — the kidneys were understood as the seat of the deepest emotions and will (Ps 7:9; 26:2; Jer 11:20); their 'failing' (consuming away) describes an intensity of longing that is physically felt.</p>",
    "28": "<p><em>kî tōʾmᵉrû maddûaʿ nirḏāp̄-lô wᵉšōreš dāḇār nimṣāʾ-bî</em>: 'If you say, &#8220;Why are we still pursuing him?&#8221; when the root of the trouble lies within him.' Job addresses a hypothetical future conversation the friends might have. <em>Šōreš dāḇār</em> (root of the matter/word) — the friends assume the root of Job's problem is internal sin; Job knows the root of the matter is the divine action described in vv.6-12. The word <em>šōreš</em> (root) is taken up by God himself in 42:7-8, reversing the friends' diagnosis: the root of the problem was their incorrect speech about God, not Job's concealed sin.</p>",
    "29": "<p><em>gûrû lāḵem mippᵉnê-ḥereb kî-ḥēmāh ʿăwōnôt ḥāreb lᵉmaʿan tēḏᵉʿûn šaddāy</em>: 'Fear the sword, for wrath brings the sword's punishment, so that you may know there is indeed a judgment.' Job's warning is a reversal of the retribution principle the friends have been applying to him: the sword does not threaten Job but the friends, whose wrath-driven pursuit constitutes the actual sin requiring judgment. <em>Šaddāy</em> — <em>ʾēl šaddāy</em> (God Almighty) is the divine name used almost exclusively in the book of Job (31 of the 48 total OT occurrences), emphasizing the overwhelming sovereign power of God before whom all judgment ultimately stands.</p>"
  },
  "20": {
    "1": "<p><em>wayyaʿan ṣôp̄ar hannaʿᵃmāṯî wayyōʾmar</em>: 'Then Zophar the Naamathite answered and said.' Zophar's second and final speech (ch.20) is his response to Job's great Redeemer declaration (19:25-27). His reply does not engage Job's vision of vindication; instead he reaches past it to reassert the classical retribution doctrine with escalating rhetorical ferocity. The deliberate non-engagement with Job's confession is revealing: the friends are unable to process a claim that exceeds their theological framework.</p>",
    "2": "<p><em>lāḵēn śēʿîpāy yᵉšîḇûnî ûḇaʿăḇûr ḥûšî bî</em>: 'Therefore my thoughts push me to answer; I feel urgency within me.' <em>Śāʿap̄</em> (thoughts that agitate, troubled reflections — from <em>śāʿap̄</em> = to split, divide) — Zophar's inner turmoil drives the speech. His urgency is presented as intellectual compulsion rather than compassionate response to Job's suffering. The contrast with Job's anguished speech (ch.19) is sharp: where Job's emotion was grief and longing, Zophar's is irritated argument.</p>",
    "3": "<p><em>mûsar kelimmaṯî ʾešmaʿ wᵉrûaḥ mibbinatî yaʿănênî</em>: 'I hear a reproof that dishonors me, and a spirit from beyond my understanding compels me.' <em>Kelimmāh</em> (dishonor, shame, humiliation) — Zophar feels personally shamed by Job's arguments. <em>Rûaḥ mibbinatî</em>: 'a spirit from beyond/out of my understanding' — Zophar claims to be moved by something beyond his normal rational process, adding prophetic authority to his speech. Yet the content of his speech is entirely conventional; the claim of spiritual compulsion underscores how readily such claims are made in the defense of traditional theology.</p>",
    "4": "<p><em>hă-zōʾt yāḏaʿtā minnî-ʿad minnî śîm ʾādām ʿălê-ʾāreṣ</em>: 'Do you not know this from of old, since man was placed upon the earth?' Zophar opens his argument by appealing to tradition — the appeal to antiquity (<em>minnî-ʿad</em> = from of old, from then on) is the standard wisdom-school move. The appeal to what 'everyone has always known' insulates the argument from critical examination. Job has already challenged this move (12:3, 9-10) by pointing to the observable world contradicting the traditional teaching.</p>",
    "5": "<p><em>kî rinnāt rᵉšāʿîm miqārôḇ wᵉśimḥat ḥānēp̄ ʿăḏê-rāgaʿ</em>: 'That the triumph of the wicked is short, and the joy of the godless lasts but a moment.' <em>Rinnāh</em> (triumphal shout, ringing cry of joy) — the emotional peak of the wicked's prosperity. <em>ʿĂḏê-rāgaʿ</em>: 'until a moment' — the brevity is emphatic. Zophar's assertion about the wicked's brief prosperity is the central claim of his speech; Job will systematically refute it in ch.21 by pointing to the observable fact that the wicked often live long and prosper to old age.</p>",
    "6": "<p><em>ʾim-yaʿăleh laššāmayim śiʾô wᵉrōʾšô lāʿāḇ yaggiʿa</em>: 'Though his greatness mounts to the heavens and his head reaches the clouds.' The imagery of sky-high ambition echoes the tower of Babel (Gen 11:4) and prophetic mockery of Babylon (Isa 14:13-14). The wicked man's vertical ambition — his claim to heaven-touching greatness — is the setup for the fall in v.7. The contrast between v.6 (sky-height) and v.7 (dung) is deliberately grotesque: the height of human self-assertion collapses into the most degraded imagery.</p>",
    "7": "<p><em>kᵉgāllô lānetsaḥ yōʾḇēḏ rōʾāyw yōʾmᵉrû ʾayyô</em>: 'He will perish forever like his own dung; those who saw him will say, &#8220;Where is he?&#8221;' <em>Gāllāh</em> (his dung, his own excrement) — one of the Bible's most blunt uses of scatological language to illustrate the worthlessness of the wicked's legacy. The fall from cloud-height (v.6) to dung (v.7) is the sharpest possible contrast. The rhetorical question <em>ʾayyô</em> (where is he?) echoes the divine question to Cain (Gen 4:9) and becomes a funeral formula: what once seemed great has vanished without a trace.</p>",
    "8": "<p><em>kᵉḥălôm yāʿûp̄ wᵉlōʾ yimṣāʾûhû wayyûḏad kᵉḥezyôn lāylāh</em>: 'He flies away like a dream and cannot be found; he is chased away like a vision of the night.' The dream/night-vision double comparison emphasizes insubstantiality: both are experiences of reality that dissolve upon waking. <em>Ḥalôm</em> (dream) and <em>ḥezyôn lāylāh</em> (vision of the night) are related but distinct terms. The wicked man's greatness is phenomenological — subjectively experienced as real but ontologically empty, gone when the dawn of judgment comes.</p>",
    "9": "<p><em>ʿayin šᵉzāp̄athu wᵉlōʾ-tôsîp̄ wᵉlōʾ-ʿôḏ tᵉšûrennû māqômô</em>: 'The eye that saw him will see him no more; his own place will no longer recognize him.' The personification of the wicked man's place (<em>māqôm</em>) as having memory — the place that knew him will no longer recognize him — adds cosmic weight. The language echoes the prophetic passages where the land mourns the absence of the departed wicked (Isa 14:16-17) and anticipates Revelation's erasure of the wicked from the book of life.</p>",
    "10": "<p><em>bānāyw yᵉraṣṣû ḏallîm wᵉyāḏāyw tāšêṣnāh ʾônô</em>: 'His children will seek favor from the poor, and his own hands will give back their wealth.' The reversal extends to the next generation: the children of the formerly prosperous wicked are reduced to begging from the poor — the exact people their father oppressed. <em>Tāšêṣnāh ʾônô</em>: 'his hands will restore/give back his wealth' — the restitution principle: ill-gotten gain is returned, whether by compulsion or divine judgment. The children of the wicked inherit not wealth but obligation.</p>",
    "11": "<p><em>ʿăṣāmōṯāyw mālaʾû ʿălûmôṯāyw wᵉʿimmô ʿal-ʿāp̄ār tiškāḇ</em>: 'His bones are full of the sins of his youth; they will lie down with him in the dust.' <em>ʿĂlûmôt</em> (youthful vigor, the vitality of youth) — his bones are saturated with the stored-up sin-energy of his youth; when he dies, this accumulated sin lies down with him. The image presents sin as a physical substance that inhabits the body — an almost material conception of moral corruption. The dust-bed destination (<em>ʿāp̄ār</em>) connects to the creation-and-death framework of Gen 3:19.</p>",
    "12": "<p><em>ʾim-tāʾēraḇ bᵉp̄îw rāʿāh yaḵᵉḥîḏennāh taḥat lᵉšônô</em>: 'Though evil is sweet in his mouth and he hides it under his tongue.' The sweetness-of-evil imagery has wide resonance: Prov 9:17 ('stolen water is sweet'), Ezek 3:3 (the scroll sweet in the prophet's mouth). The hiding under the tongue is a culinary metaphor — savoring, like wine held under the tongue before swallowing. The pleasure precedes the poison. <em>Tāʾab</em> (to be sweet) connects to the enticement of sin that Proverbs consistently addresses: evil presents itself as desirable before revealing its destructive nature.</p>",
    "13": "<p><em>yaḥmōl ʿāleyhā wᵉlōʾ yaʿazᵉḇennāh waymannaʿennāh bᵉṯôḵ ḥikkô</em>: 'Though he spares it and will not let it go, but keeps it lodged in his palate.' The extended oral-retention metaphor (v.12-14) presents the wicked man as unable to release what he knows will destroy him — gripping pleasurable evil in his mouth even as it turns. <em>Ḥēḵ</em> (palate, roof of the mouth) — the most sensory part of tasting. The man is so habituated to the sweetness of evil that he cannot spit it out even when its venom is revealed. The structural parallel to addiction is striking.</p>",
    "14": "<p><em>laḥmô bᵉmēʿāyw nehpāḵ mᵉrôrat pᵉtānîm bᵉqirbô</em>: 'Yet his food turns in his stomach; it becomes cobra venom (<em>rōʾš</em>, <em>mᵉrôrat pᵉtānîm</em>) inside him.' <em>Rōʾš</em> (gall, bitter herb, venom) and <em>mᵉrôrat pᵉtānîm</em> (venom of cobras) — cobra poison was one of the most feared in the ANE. The reversal of sweetness to venom inside the body is Zophar's central biological metaphor for retribution: what was consumed as pleasure becomes the poison that destroys from within. This is moral physiology — the nature of sinful pleasure is self-destructive at a fundamental level.</p>",
    "15": "<p><em>ḥayil bālaʿ wayyᵉqîʾennû mibbiṭnô yôrišennû ʾēl</em>: 'He swallowed wealth down and will vomit it up again; God will expel it from his belly.' <em>Bālaʿ</em> (swallow, engulf) — a violent consuming. <em>Qîʾ</em> (vomit up) is rare and deliberately crude. God is the active agent of the expulsion: what was consumed as wealth is ejected by divine force. The image is the inverse of receiving a divine gift: God gives by provision, but what is seized unjustly God takes back by extraction. The stomach as the seat of greed that cannot retain its ill-gotten contents.</p>",
    "16": "<p><em>rōʾš-pᵉtānîm yinqāq waharg-lô leššôn ʾep̄ʿeh</em>: 'He will suck the venom of cobras; the tongue of the viper will kill him.' The cobra imagery continues: what he swallowed as food turns out to be venom; what he sucks seeking nourishment is poison. The <em>peten</em> (asp/cobra) and <em>ʾep̄ʿeh</em> (viper) are two distinct venomous snakes. The tongue of the viper — the instrument of both deception and injection — is the agent of his death. The serpent imagery connects to the Eden narrative (Gen 3:1-5) where serpentine deception first presented evil as sweet and desirable.</p>",
    "17": "<p><em>ʾal-yirʾeh bipelaggôt nᵉhārôt naḥălê devāš waḥemʾāh</em>: 'He will not look upon the rivers, the flowing channels, the streams of honey and butter.' The positive imagery of abundance — honey, butter, flowing rivers — is denied to the wicked. This is a promised-land refusal: the wicked man is excluded from the <em>eretz zāḇat ḥālāḇ ûḏᵉḇaš</em> (land flowing with milk and honey, Exod 3:8) that represents YHWH's provision. What the righteous inherit, the wicked are barred from — not by geography but by the moral logic of their own choices.</p>",
    "18": "<p><em>mᵉšîḇ yāgāʿ wᵉlōʾ yiḇlāʿ ḵᵉḥêl tᵉmûrāṯô wᵉlōʾ yaʿălōs</em>: 'He must restore the fruits of his labor without consuming them; his restitution will be according to his wealth, and he shall not enjoy it.' The principle of <em>šāḇ</em> (restoring/returning) — what he earned by exploitation he must give back. The commercial vocabulary (<em>yāgāʿ</em> = labor, toil; <em>tᵉmûrāh</em> = exchange value, barter price) makes this a legal financial restitution. The double negative pleasure-denial: he returns what he earned and cannot even enjoy the process of exchange.</p>",
    "19": "<p><em>kî-rāṣaṣ ʿāzaḇ dallîm bêt gāzal wᵉlōʾ yiḇnēhû</em>: 'For he oppressed and abandoned the poor; he seized a house he did not build.' The ethical charge that grounds the punishment: <em>rāṣaṣ</em> (to crush, oppress, break) the poor — the word used in Isa 58:6 ('untie every yoke') and Luke 4:18 ('to set the oppressed free' — <em>rᵉṣûṣîm</em>). He seized (<em>gāzal</em> = take by force, rob) a house he did not build — the Naboth's vineyard dynamic (1 Kgs 21) where the powerful seize what belongs to the vulnerable. The punishment (vv.20-28) is proportioned to the offense.</p>",
    "20": "<p><em>kî lōʾ yāḏaʿ šāleū bᵉbiṭnô bᵉḥămûḏô lōʾ yimmalēṭ</em>: 'He will not feel peace (<em>šālem</em>) within; he will retain nothing of what he desired.' <em>Šālem</em> (peace, completeness, wholeness — shalom root) within his belly: the man who seized prosperity by violence cannot experience the inner wholeness that is the organic result of righteous living. <em>Ḥāmaḏ</em> (desire, covet) — the verb of the tenth commandment (Exod 20:17; Deut 5:21). Coveting generates restlessness, not satisfaction: the very desire-structure that drove the acquisition undermines the enjoyment of it.</p>",
    "21": "<p><em>ʾên-śārîḏ lᵉʾoḵlô ʿal-kēn lōʾ-yāḥîl ṭûḇô</em>: 'Nothing is left of his food; therefore no one will inherit his prosperity.' <em>Śārîḏ</em> (survivor, remnant) — the word used for the remnant of Israel (Isa 1:9; 10:20; Joel 2:32). When nothing survives of what he consumed, there is no legacy. The theological irony: the man who consumed and hoarded has no remainder — no remnant of food, no remnant of children to inherit. The family-legacy termination is Zophar's most pointed threat, striking at the ANE's deepest investment: perpetuation through heirs.</p>",
    "22": "<p><em>bimᵉlōʾ śipqô yēṣar lô kol-yāḏ ʿāmēl tāḇôʾ-ʿālāyw</em>: 'In the fullness of his plenty he will be in distress; every hand of the suffering will come against him.' The paradox: his maximum prosperity coincides with maximum distress. <em>Śipeq</em> (plenty, sufficiency, fullness) — he achieves abundance; at that exact moment (<em>yēṣar lô</em> = he will be pressed, in straits) the distress arrives. The phrase reverses the normal expectation: fullness brings comfort, not anguish. The arriving hands of the <em>ʿāmēl</em> (those who toil/suffer) are the oppressed he once crushed, now rising against him.</p>",
    "23": "<p><em>yᵉhî lᵉmalēʾ biṭnô yᵉšallaḥ-bô ḥărôn ʾappô wayyamṭēr ʿālāyw bilᵉḥûmô</em>: 'When he is set to fill his belly, God will hurl his fierce anger upon him and rain it down on him as he eats.' <em>Šālaḥ ḥărôn ʾap̄</em> (send/hurl fierce anger) — divine wrath as a thrown weapon. <em>Māṭar</em> (to rain) — used of the Sodom judgment (Gen 19:24: 'YHWH rained sulfur and fire') and the plagues (Exod 9:18). The eating imagery is deliberate: the man who seized others' food will find that while eating, divine judgment falls on him.</p>",
    "24": "<p><em>yibrāḥ minnešeq bārzel tiḥᵉlᵉp̄ennû qešeṯ nᵉḥûšāh</em>: 'He flees from the iron weapon, and the bronze bow strikes him through.' The double military imagery of flight and pursuit: even fleeing the iron weapon (<em>neše</em>) the man is struck by the bronze bow (<em>qešeṯ nᵉḥûšāh</em>). Inescapability of divine judgment is the theme — there is no direction to flee that avoids the sentence. The combination of two weapon-types (iron = short-range; bronze bow = long-range) suggests omnidirectional pursuit with no gap.</p>",
    "25": "<p><em>šālaph wayyēṣēʾ miggēwāh ûḇārāq mimmᵉrārāṯô yahalōk ʿālāyw ʾêmîm</em>: 'The arrow is drawn; it comes out through his body; the gleaming blade exits through his gall; terrors (<em>ʾêmîm</em>) come upon him.' <em>Bārāq</em> (lightning bolt, gleaming metal) — the sword blade gleaming as it exits is a vivid martial image. <em>Mᵉrōrāh</em> (gall, bile) — the arrow or sword passes through the organ of bitterness; as the blade exits it draws out the gall that symbolizes his bitter accumulated evil. <em>ʾÊmîm</em> (terrors) — the same word used in 9:34 for Job's fear of God; here divine terrors accompany the physical death.</p>",
    "26": "<p><em>kōl-ḥōšeḵ ṣāpûn liṣᵉpûnāyw tᵉʾaḵlēhû ʾēš lōʾ-nuppāḥ yērāʿ śārîḏ bᵉʾohᵃlô</em>: 'All darkness is stored up for his treasures; a fire not fanned by wind will consume him; disaster will destroy what remains in his tent.' <em>Ḥōšeḵ ṣāpûn liṣᵉpûnāyw</em>: 'darkness stored up for his stored-up things' — the wordplay (<em>ṣāpûn</em> twice) equates his treasure-hoarding with the darkness stored for his destruction: he stored, and darkness is stored for him. <em>ʾĒš lōʾ-nuppāḥ</em> (fire not blown upon) — spontaneous, self-sustaining divine fire, not human-kindled; the same quality as the fire of Sodom (Gen 19:24).</p>",
    "27": "<p><em>yᵉgallû šāmayim ʿăwônô wᵉʾereṣ miṯqōmāmāh lô</em>: 'The heavens will expose his guilt, and the earth will rise up against him.' The cosmic witness against the wicked: heaven above and earth below both testify to his iniquity. <em>Gālāh</em> (to expose, uncover, reveal) is the verb of the prophetic disclosure of hidden things (Amos 3:7: 'he reveals his secrets to his servants'). The earth 'rising' against him (<em>qûm lô</em>) personifies creation as judge — a motif seen in Isa 1:2 (heaven and earth as YHWH's witnesses) and Rev 20:11 (the earth and heaven fleeing from the judgment throne).</p>",
    "28": "<p><em>yiggāl yᵉḇûl bêṯô niggārôṯ bᵉyôm ʾappô</em>: 'The produce of his house will be carried away; his possessions will pour away in the day of his anger.' <em>Nāgar</em> (to flow, pour out) — liquid imagery for total dispersal of wealth: like water, it cannot be held. <em>Yôm ʾappô</em> (the day of his anger) — ambiguous pronoun: could be God's anger or the wicked man's anger. Most likely God's; 'the day of wrath' is standard eschatological-judgment language (Zeph 1:15; Prov 11:4). The house that symbolized his wealth and dynasty is emptied out.</p>",
    "29": "<p><em>zeh ḥēleq-ʾādām rāšāʿ mēʾĕlōhîm wᵉnaḥălat ʾimrô mēʾēl</em>: 'This is the portion (<em>ḥēleq</em>) of the wicked man from God — the heritage (<em>naḥălāh</em>) decreed for him by God.' The summary verdict. <em>Ḥēleq</em> (portion, lot, assigned share) and <em>naḥălāh</em> (inheritance, heritage) are both used for Israel's covenantal inheritance of the land; here applied to the wicked man's 'inheritance' of judgment. The formulaic ending (<em>mēʾēl</em> = from God) makes the retribution explicitly theological: this is not mere natural consequence but divine assignment. Job will contest this portrait in ch. 21 by pointing to observable reality.</p>"
  },
  "21": {
    "1": "<p><em>wayyaʿan ʾîyôḇ wayyōʾmar</em>: 'But Job answered and said.' Job's reply in ch. 21 is his most sustained and direct confrontation with the friends' retribution theology. It is also his most intellectually rigorous speech: he does not appeal to his own innocence (that was ch. 16-17, 19) but to observable reality — the empirical observation that the wicked frequently prosper and die peacefully. The chapter is a systematic dismantling of Zophar's thesis in ch. 20.</p>",
    "2": "<p><em>šimᵉʿû šāmôaʿ millatî wᵉhî tᵉhî tanḥûmōṯêḵem</em>: 'Listen carefully to what I say; let this be your consolation.' <em>Šāmôaʿ šāmaʿ</em> (infinitive absolute + finite verb = listen carefully, truly listen) — the imperative doubled for emphasis. The sardonic offer: 'let my listening be your consolation' reverses the normal consolation formula. The friends came to console Job (2:11); he asks instead that they accept consolation by listening to his refutation of their theology. The consolation they owe him they will receive by being corrected.</p>",
    "3": "<p><em>śᵉʾûnî wᵉʾānōḵî ʾăḏabbēr wᵉʾaḥar ḏabbᵉrî talʿîg</em>: 'Bear with me so I may speak; and after I have spoken, mock away.' <em>Śāʾ</em> (to lift, bear, endure) — 'endure me, carry me through this speech.' Job asks for the minimal courtesy of an uninterrupted hearing before the mockery begins. The offer to let them mock afterward has a brittle dignity: he does not expect understanding, only silence long enough to make the argument. The Hebrew word for 'mock' (<em>lāʿag</em>) is the same used of enemies mocking in the Psalms (Ps 22:7; 44:13).</p>",
    "4": "<p><em>hăʾānōḵî lᵉʾādām śîḥî wᵉʾim-maddûaʿ lōʾ-tiṣr rûḥî</em>: 'As for me, is my complaint directed to man? Why then should I not be impatient?' <em>Śîaḥ</em> (complaint, meditation, musing) — Job distinguishes the addressee of his complaint: it is directed to God (<em>ʾĕlôah</em>), not to humans. If God is his interlocutor and God is silent, his impatience (<em>qāṣar rûaḥ</em> = short of breath/spirit, frustrated, impatient) is understandable. The distinction matters: his complaint is a theological dispute, not a social one, and therefore does not require the friends' approval or resolution.</p>",
    "5": "<p><em>pᵉnû ʾēlay wᵉhiššāmmû wᵉśîmû yaḏ ʿal-peh</em>: 'Look at me and be appalled; lay your hand over your mouth.' <em>Šāmam</em> (to be appalled, devastated, deserted) — the same root used of the desolated temple (Dan 9:27; 11:31; 12:11) and waste land. Job's condition is so extreme that visual encounter with it should produce the physical gesture of stunned silence: <em>śîm yaḏ ʿal-peh</em> (lay the hand over the mouth) is the gesture of awed, speechless respect (Job 29:9; 40:4; Mic 7:16). Job is asking the friends to consider that what they are seeing should silence their comfortable theodicy.</p>",
    "6": "<p><em>wᵉʾim-zāḵarᵉtî wᵉniḇhāltî ûʾāḥaz bᵉśārî palāṣûṯ</em>: 'Even when I think of it I am troubled; shuddering seizes my flesh.' <em>Nāḇah</em> (niphal = to be terrified, overwhelmed) and <em>pālaṣ</em> (shuddering, shivering with horror — a hapax). The physical response (shuddering flesh) to intellectual reflection on his question anticipates the divine speech from the whirlwind (chs. 38-41) where the appropriate human response to God's question-fronted reality is precisely this awe. Job is epistemically honest: the question he is about to ask is one that genuinely disturbs him, not a rhetorical device.</p>",
    "7": "<p><em>maddûaʿ rᵉšāʿîm yiḥyû ʿāṯᵉqû gam-gāḇᵉrû ḥāyil</em>: 'Why do the wicked go on living, grow old, and even grow mighty in power?' The central theodicy question that runs through the Psalms of Asaph (Ps 73:3-12), Jeremiah's complaints (Jer 12:1-2), Habakkuk (Hab 1:2-4), and Ecclesiastes (Eccl 7:15; 8:14). <em>Yiḥyû</em> (they live, they go on living), <em>ʿāṯaq</em> (to grow old — the opposite of dying young), <em>gāḇar ḥāyil</em> (grow mighty in strength) — the triple accumulation describes not just survival but increasing prosperity. This directly contradicts Zophar's claim in 20:5 that 'the triumph of the wicked is short.'</p>",
    "8": "<p><em>zarʿām nāḵôn lip̄nêhem ʿimmām ûṣeʾĕṣāʾêhem lᵉʿênêhem</em>: 'Their children are established around them, and their offspring before their eyes.' In the ANE theological framework, prosperous descendants were the primary sign of divine favor. The wicked man sees his children and grandchildren growing up in front of him — the most concrete embodiment of blessing and continuity. This too directly contradicts the standard retribution formula which should see the wicked man's family cut off (cf. Ps 37:28; Prov 14:11).</p>",
    "9": "<p><em>bāttêhem šālôm mippāḥad wᵉlōʾ šêḇeṭ ʾĕlôah ʿălêhem</em>: 'Their houses are safe from fear; the rod of God is not upon them.' <em>Šālôm mippāḥad</em> (peace from fear) — the kind of security promised to the righteous (Prov 1:33; Ps 91:5) is actually enjoyed by the wicked. <em>Šēḇeṭ ʾĕlôah</em> (the rod/staff of God) — the instrument of discipline and judgment is conspicuously absent from the wicked man's household. The observation is theologically scandalous: the God who should be punishing them is apparently protecting them instead.</p>",
    "10": "<p><em>šôrô ʿibbār wᵉlōʾ yiḡʿāl pārāṯô pālᵉṭāh wᵉlōʾ tᵉšakkēl</em>: 'Their bull breeds without fail; their cow calves without miscarriage.' Agricultural fertility and successful livestock reproduction were direct signs of covenant blessing (Deut 28:4; 28:11). The wicked man's animals breed reliably — the same blessing promised to obedient Israel is enjoyed by those who refuse God (v.14-15). The biological evidence of divine favor is distributed without apparent moral sorting.</p>",
    "11": "<p><em>yᵉšallᵉḥû kᵉṣōʾn ʿᵉwîlêhem wᵉyaldêhem yᵉraqᵉḏûn</em>: 'Their little ones run out like a flock, and their children dance.' The festive domestic image of children and dancing is the biblical picture of a community at peace and flourishing (Jer 31:13; Zech 8:5; Ps 30:11). The wicked man's household is characterized by exactly the visible joy and abundance that his theology should have denied him. The dancing children are a pointed counter-image to the suffering Job's household (ch. 1-2) where real piety produced disaster.</p>",
    "12": "<p><em>yiśśᵉʾû ṯōp̄ wᵉḵinnôr wayyiśmᵉḥû lᵉqôl ʿûḡāḇ</em>: 'They take up timbrel and harp and rejoice at the sound of the flute.' Three instruments: <em>tōp̄</em> (timbrel/tambourine), <em>kinnôr</em> (lyre/harp), <em>ʿûḡāḇ</em> (a wind instrument, possibly pipes or flute). The same instruments associated with worship and celebration (Ps 150:3-5; 1 Sam 10:5) are here in the hands of those who reject God (v.14). The irony is deliberate: the wicked celebrate with the same music Israel uses for divine praise, and their celebration is not interrupted by divine judgment.</p>",
    "13": "<p><em>yᵉḵallû ḇaṭṭôḇ yᵉmêhem ûḇeregaʿ šᵉʾôl yēḥāṯû</em>: 'They spend their days in prosperity and go down to Sheol peacefully (<em>bᵉrageaʿ</em>).' <em>Bālāh</em> (to wear out, finish off, exhaust) is used of clothes wearing out (Deut 8:4; 29:5; Josh 9:13) and of time being consumed; here their days are 'worn out' in prosperity — fully spent in good. <em>Bᵉrageaʿ šᵉʾôl yēḥāṯû</em>: 'in a moment they go down to Sheol' — a peaceful, sudden death in old age at the peak of prosperity, not the prolonged dying of the punished wicked that Zophar described. The contrast with Job's prolonged suffering is implicit and pointed.</p>",
    "14": "<p><em>wayyōʾmᵉrû lāʾēl sûr mimmennû wᵉḏaʿat dᵉrāḵeḵā lōʾ ḥāp̄āṣnû</em>: 'Yet they say to God, &#8220;Leave us alone; we do not want to know your ways.&#8221;' Job quotes the wicked man's own words — their explicit rejection of God. <em>Sûr mimmennû</em> (depart from us) echoes Israel's wilderness rebellion and the prophetic accusation that the people have turned away from YHWH (Isa 30:11; Jer 2:31). The explicit rejection of divine instruction (<em>ḏaʿat dᵉrāḵeḵā</em>) while enjoying full material prosperity is the datum that destroys simple retribution theology: prosperity is not correlated with piety in observed experience.</p>",
    "15": "<p><em>mah-šaddāy kî naʿăḇᵉḏennû ûmah-nôʿîl kî nip̄gᵉʿ-bô</em>: 'Who is the Almighty that we should serve him? What do we gain by praying to him?' The wicked man's explicit calculus: God is worth serving only if the service produces material benefit. <em>Yāʿal</em> (to profit, benefit, avail) — what is the return on investment of prayer and obedience? This is the same transactional theological framework the Adversary implied in 1:9-10 ('Does Job fear God for nothing?'). The wicked man's explicit utilitarian theology is the dark mirror of the Adversary's accusation against Job's piety.</p>",
    "16": "<p><em>hēn lōʾ ḇᵉyādām ṭûḇām ʿăṣat rᵉšāʿîm rāḥᵉqāh mimmennî</em>: 'Indeed, their prosperity is not in their own hand — the counsel of the wicked is far from me.' Job makes an important qualification: the wicked man's prosperity is not self-generated but is within God's domain. This prevents a deistic conclusion (the wicked prosper because God is absent). Job is insisting that divine sovereignty extends to the wicked's prosperity — God allows it — while simultaneously distancing himself from the wicked man's theology (<em>rāḥᵉqāh mimmennî</em> = I keep far from me).</p>",
    "17": "<p><em>kammāh nēr-rᵉšāʿîm yiḏʿāḵ wᵉyāḇōʾ ʿălêhem ʾêḏām ḥᵉḇālîm bᵉʾappô yᵉḥallēq</em>: 'How often is the lamp of the wicked actually extinguished? How often does disaster come upon them? God distributes pain in his anger.' <em>Nēr rᵉšāʿîm</em> (lamp of the wicked) — the friends promised this lamp would be put out (18:5-6), but Job asks: how often does this actually happen? The rhetorical question (<em>kammāh</em> = how many times?) implies: rarely, or less often than the friends claim. The empirical challenge: observable experience contradicts the confident assertion of retribution theology.</p>",
    "18": "<p><em>yihyû kᵉteḇen lip̄nê-rûaḥ ûkᵉmōṣ gānāḇathu sûp̄āh</em>: 'They are as straw before the wind, and chaff swept away by the tempest.' Job does not deny that the wicked sometimes face judgment; his challenge is the frequency and consistency that the friends assert. The images of straw/wind and chaff/storm are the standard biblical metaphors for the wicked's fate (Ps 1:4; Isa 17:13; Hos 13:3). Job acknowledges these happen — but how often? The point is the gap between theological assertion and empirical frequency.</p>",
    "19": "<p><em>ʾĕlôah yiṣp̄ōn laḇānāyw ʾônô yᵉšallem ʾēlāyw wᵉyēḏāʿ</em>: 'You say, &#8220;God stores up the father&#8217;s punishment for his children.&#8221; Let him repay the man himself and he will know it.' Job attacks a specific theodicy escape route: when the wicked man himself does not suffer, appeal is made to his children bearing the punishment (Exod 20:5; Deut 5:9). Job demands direct personal punishment: if God is just, the transgressor himself should know it, not merely his descendants. <em>Yēḏāʿ</em> (he will know/experience it) — the experiential knowledge that comes from direct encounter with consequences.</p>",
    "20": "<p><em>yirʾû ʿênāyw kîḏô wᵉmēḥămaṯ šaddāy yišteh</em>: 'Let his own eyes see his destruction; let him drink of the wrath of the Almighty.' The demand for first-person moral experience: the transgressor's own eyes (<em>ʿênāyw</em>) must witness his judgment, not a surrogate's. <em>Šāṯāh ḥămaṯ šaddāy</em> (drink the wrath of the Almighty) — the cup of divine wrath is one of the OT's most vivid judgment images (Ps 75:8; Isa 51:17, 22; Jer 25:15-17; Rev 14:10; 16:19). Job insists that moral accountability requires direct personal experience, not generational displacement.</p>",
    "21": "<p><em>kî mah-ḥep̄ṣô bᵉḇêṯô ʾaḥărāyw ûmispar ḥodāšāyw ḥuṣṣāṣû</em>: 'For what pleasure does he take in his house after him, when the number of his months is severed?' The forward-looking question: once the man himself is dead, what does he care about his house and posterity? The logic undermines the delayed-generational-punishment argument: if the wicked man is dead, he has no experiential stake in the fate of his children. Justice requires contemporaneous consequences, not posthumous ones. <em>Ḥāṣaṣ</em> (to cut, divide, sever) — his months are 'cut short' in death.</p>",
    "22": "<p><em>hăʾēl yᵉlammēḏ-dāʿat wᵉhûʾ rāmîm yišpôṭ</em>: 'Will anyone teach God knowledge? He is the one who judges those on high.' A rhetorical boundary-setting: the question in v.7 (why do the wicked prosper?) does not license human instruction of God about how to run his moral universe. <em>Rāmîm</em> (the high ones, the exalted) — possibly angels or heavenly beings; God judges those above Job's level. The acknowledgment of God's sovereignty does not resolve Job's theodicy question but prevents the question from becoming an attempt to rewrite God's governance. The tension between epistemic humility and honest complaint is sustained rather than resolved.</p>",
    "23": "<p><em>zeh yāmûṯ bᵉʿeṣem tummô kullô šalʾănān wᵉšāleō</em>: 'One person dies in full vigor (<em>bᵉʿeṣem tummô</em>), completely at ease and secure.' <em>ʿOṣem</em> (bone, strength, essence) + <em>tōm</em> (completeness, integrity, wholeness) — 'in the very bone of his completeness'; at the apex of his strength and life-fullness. <em>Šalʾănān wᵉšāleō</em> (at rest and at ease) — the state of prosperous security that Ps 73:12 describes as the wicked man's condition. The observation in vv.23-26 is deliberately universal: all kinds of people die, with no apparent moral correlation to their quality of death.</p>",
    "24": "<p><em>ʿăṭînāyw mālᵉʾû ḥālāḇ ûmaḥ ʿaṣᵉmôṯāyw yᵉšuqqeh</em>: 'His sides full of milk and his bones saturated with marrow.' The physical description of peak-health death: <em>ḥālāḇ</em> (milk/fat — used figuratively for abundant nourishment) and <em>maḥ</em> (marrow — the innermost richness of the bones). Both are images of abundant interior nourishment — this man dies with every biological indicator of flourishing. The grotesque health at death makes the contrast with Job (whose bones burn with fever, 30:17; whose skin clings to his bones, 19:20) all the more pointed.</p>",
    "25": "<p><em>wᵉzeh yāmûṯ bᵉnep̄eš mārāh wᵉlōʾ-ʾāḵal baṭṭôḇāh</em>: 'Another person dies in bitterness of soul, having never tasted what is good.' The exact opposite life-trajectory to v.23-24: <em>nep̄eš mārāh</em> (bitter of soul) — the phrase used of Hannah (1 Sam 1:10) and Naomi (Ruth 1:20: 'call me Mara, for the Almighty has dealt bitterly with me'). This person has suffered throughout life and has 'not eaten of the good' — never experienced the prosperity that should, according to retribution theology, reward the righteous. The pairing of vv.23-26 presents four deaths that cut across the moral categories: prosperous death, bitter death — then...</p>",
    "26": "<p><em>yaḥḏāw ʿal-ʿāp̄ār yiškaḇû ûrimāh tᵉḵassēh ʿălêhem</em>: 'They lie down together in the dust, and worms cover them both.' <em>Yaḥḏāw</em> (together) — the most theologically loaded word in the verse. The prosperous man of v.23-24 and the bitter man of v.25 lie together, undifferentiated in death. <em>Rimmāh</em> (worm, maggot) covers them equally — the same image of final corruption for all flesh (Isa 14:11; 66:24; Job 17:14). The leveling of death cuts through all moral sorting: the grave receives the righteous and wicked alike without apparent distinction, which is exactly the empirical observation that makes retribution theology inadequate as a complete account of divine justice.</p>",
    "27": "<p><em>hēn yāḏaʿtî maḥšᵉḇôṯêḵem ûmᵉzimmôṯ ʿālay taḥmōsû</em>: 'I know your thoughts and the schemes you wrongfully contrive against me.' Job names the interpretive move the friends are about to make: <em>maḥăšāḇôt</em> (plans, schemes, inner thoughts) and <em>mᵉzimmôt</em> (devious plans, malicious intentions — from <em>zāmam</em> = to plan evil). The friends will argue that Job is the wicked man of their description; Job preempts this by naming it as a wrong (<em>tāḥmōs</em> = to do violence to, wrong) and demonstrating that he knows their rhetorical play before they execute it.</p>",
    "28": "<p><em>kî tōʾmᵉrû ʾayēh bêṯ-nāḏîḇ wᵉʾayēh ʾōhel miškᵉnôṯ rᵉšāʿîm</em>: 'For you say, &#8220;Where is the house of the noble man? Where are the dwelling places of the wicked?&#8221;' The friends' implied argument: the prosperity of the wicked is always destroyed — look, their houses are gone, their tents ruined. The rhetorical question (<em>ʾayēh</em> = where is it?) implies the answer is 'destroyed,' validating retribution theology. Job will rebut this with a traveler's report (v.29-31): the evidence from the roads tells a different story.</p>",
    "29": "<p><em>hălōʾ šᵉʾaltum ʿôḇᵉrê ḏāreḵ wᵉʾōṯōṯām lōʾ tᵉnakkērû</em>: 'Have you not asked those who travel the roads? Do you not recognize their evidence?' Job appeals to empirical testimony — travelers who have observed the world broadly, not just within the friends' theological tradition. <em>ʿôḇᵉrê ḏāreḵ</em> (those who pass by on the road) — witnesses who have seen many places and many lives. <em>ʾōṯōṯām</em> (their signs, testimonies) — the observable evidence they can report. Job's empirical method here is striking: he appeals to experience and observation against the friends' appeal to tradition (cf. Zophar's 'Do you not know from of old...?' 20:4).</p>",
    "30": "<p><em>kî leḥeḏ rāʿ yēḥāśēḵ bᵉyôm ʿeḇrôṯ yûḇālû</em>: 'That the wicked is spared on the day of disaster and delivered to the day of wrath.' The traveler's report contradicts the friends: the wicked are often <em>spared</em> on the day of disaster — not judged, but protected. <em>Yôm ʿeḇrôṯ</em> (day of wrath) — possibly a future eschatological event rather than the personal death Zophar described. Job may be acknowledging a final judgment while insisting it does not reliably operate in present experience. The gap between present observation and final accountability is the unresolved theological space the book of Job inhabits.</p>",
    "31": "<p><em>mî-yaggîḏ ʿal-pānāyw darkô ûmah-pāʿal mî yᵉšallem-lô</em>: 'Who will tell him to his face what he has done? Who will repay him for what he has done?' The double question highlights the gap between sin and observable consequence: no one confronts the powerful wicked man with his deeds while he lives, and no retributive agent appears to repay him during his lifetime. The silence of accusation and the absence of repayment during life is the empirical observation that Job offers against the friends' tidy theology of immediate retribution.</p>",
    "32": "<p><em>wᵉhûʾ liqᵉḇārôt yûḇāl wᵉʿal-gādîš yišqôḏ</em>: 'Yet he is carried to the grave, and a vigil is kept over his tomb.' The wicked man receives the full burial honors due to the respected: <em>šāqaḏ</em> (to watch, keep vigil) over his <em>gādîš</em> (tomb-mound, burial heap). This is high-status burial — a watched and honored grave. The contrast between the wicked man's death without consequences and Job's own suffering is complete: the man who rejected God (v.14-15) receives public honor in death while Job, who maintains his integrity, is abandoned and suffers.</p>",
    "33": "<p><em>māṯqû-lô riḇᵉḏê nāḥal wᵉʾaḥărāyw kāl-ʾāḏām yimšôḵ wᵉlip̄ānāyw ʾên mispar</em>: 'The clods of the valley are sweet to him, and every person follows after him, as countless as those who went before him.' <em>Māṯaq</em> (sweet, pleasant) — even the earth's embrace of the wicked is gentle. The numberless procession of humanity — those who came before and those who follow after — makes the wicked man's death part of the universal flow of mortality rather than a punitive end. He dies with the company of all humanity; his death is not a special judgment but a common destiny.</p>",
    "34": "<p><em>wᵉʾêḵ tᵉnaḥămûnî hāḇel ûtᵉšûḇôṯêḵem nišʾar māʿal</em>: 'How then do you comfort me with empty words? Your answers are nothing but falsehood!' <em>Heḇel</em> (vanity, breath, emptiness) — the key Ecclesiastes word: the friends' consolation is vapor, insubstantial. <em>Māʿal</em> (treachery, faithlessness) — a strong term used of covenant betrayal (Lev 5:15; Ezra 9:4; 1 Chr 10:13). The friends' false answers constitute not mere error but a kind of faithlessness — a betrayal of their duty as truth-speakers and consolers. Job ends the speech with the same verdict YHWH will pronounce in 42:7: 'you have not spoken of me what is right.'</p>"
  }
}

def main():
    c = load_comm('mkt-original', 'job')
    merge_comm(c, JOB)
    save_comm('mkt-original', 'job', c)
    total = sum(len(vs) for vs in JOB.values())
    print(f'job mkt-original: {total} entries written (ch19-21)')

if __name__ == '__main__':
    main()
